"""
MKT Original Commentary — Judges chapters 20–21
Run: python3 scripts/zc-original-judges-20-21.py

Source data:
- data/interlinear/judges.json
- data/translation/draft/mediating/judges.json (MKT text)

Key decisions in this range:
- kĕʾîš ʾeḥād ("as one man") — covenant-assembly formula, ironic peak after the book's fracture
- šāʾal bĕ- pattern of inquiry (vv. 18,23,27-28): registers increasing solemnity as Israel adds fasting,
  weeping, and burnt/peace offerings before the ark — three stages before YHWH answers Go
- Phinehas anchor (v.28): places Gibeah episode early in the period (not at the end), consistent
  with the epilogue being a literary insertion out of chronological order
- nāgap (v.35): first explicit divine-smiting verb applied TO Benjamin — YHWH is the agent
- zimm·āh + nĕbālāh (v. reference 19:24 already handled in ch19 script; ch20 uses the Levite's
  recap): the crime vocabulary from ch19 is carried forward in the assembly's deliberation
- Ch21: niḥam used of YHWH (v.15) and of Israel (v.6) — same root as Noah narrative and Exodus
  repentance sequences; the divine "gap" (pereṣ) acknowledges YHWH's hand in the outcome
- mōʿēd YHWH at Shiloh (v.19): the feast language sets the abduction against a sacred calendar
- Closing refrain (21:25): second use of the full formula; functions as the book's final verdict
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JUDGES = {
  "20": {
    "1": "<p><em>wayyēṣĕʾû kol-bĕnê yiśrāʾēl wayyiqqāhēl hāʿēdāh kĕʾîš ʾeḥād</em> — 'Then all the sons of Israel came out and the congregation assembled as one man.' <em>kĕʾîš ʾeḥād</em> (H259+H376, as one man) — the covenant-unity idiom that normally signals holy-war consensus (cf. 1 Sam 11:7; Ezra 3:1). Bitterly ironic: the nation achieves its only unanimous assembly not against the Canaanites (see 1:1-2, where the campaign begins without full tribal unity) but in civil war. <em>dan ʿad bĕʾēr-šebaʿ</em> (from Dan to Beersheba) — the traditional north-to-south formula for all Israel appears for the first time in Judges here, again in service of internal conflict rather than covenant conquest.</p>",
    "2": "<p><em>pinnôt kol-hāʿām kol šibṭê yiśrāʾēl biqhal ʿam hāʾĕlōhîm</em> — 'the chiefs of all the people, all the tribes of Israel, in the assembly of the people of God.' <em>ʿam hāʾĕlōhîm</em> (people of God) — the generic divine name Elohim rather than the covenant name YHWH; the phrase occurs in very few places in the narrative literature. The use of Elohim here may signal distance: Israel is still the people of God, but the divine intimacy of the covenant name is absent as they move toward fratricide. <em>ʾarbāʿāh mēʾôt ʾelep règlî šōlēp ḥāreb</em> (four hundred thousand swordsmen on foot) — the census language evokes Numbers; the army is enormous, dwarfing even David's forces.</p>",
    "3": "<p><em>wayyišmĕʿû bĕnê binyāmîn kî ʿālû bĕnê yiśrāʾēl hammiṣpāh</em> — 'The Benjamites heard that the sons of Israel had gone up to Mizpah.' Benjamin's posture throughout ch. 20 is reactive, never initiating dialogue. The assembly summons them to give account (<em>daḇrû-nā lĕʿênênû</em>, tell us) — a forensic challenge. Their silence until v.13 (refusal to hand over the guilty men) is their decision to stand with their own kinsmen rather than with covenant justice, the inverse of what Judah does in the opening chapter.</p>",
    "4": "<p><em>wayaʿan hāʾîš hallēwî ʾîš hāʾiššāh hannirṣāḥāh</em> — 'The Levite, the husband of the murdered woman, answered.' <em>nirṣāḥāh</em> (H7523, murdered/slain — the Piel of rṣḥ, which appears in the Decalogue prohibition: <em>lōʾ tirṣāḥ</em>, you shall not murder, Exod 20:13). The Levite characterizes his concubine's death with the Decalogue's forbidden act — framing the assembly's deliberation in covenant-law terms. His retelling (vv. 4-7) softens his own role while maximizing the outrage; the text does not editorialize, but the reader who knows ch. 19 notices the omissions.</p>",
    "5": "<p><em>wayyāqumû ʿālay baʿălê haggiḇĕʿāh wayyāsōḇḇû ʿālay babbayit layllāh dimmû lĕhārgēnî wĕʾet-pilagtî ʿinnû</em> — 'The men of Gibeah rose against me and surrounded the house at night. They intended to kill me, and my concubine they violated.' <em>dimmû</em> (H1819, thought/plotted — dāmāh) — the verb implies premeditated malice; they had a plan. <em>ʿinnû</em> (H6031, afflict/violate — same root as the affliction vocabulary of Egyptian slavery, Exod 1:11-12; Deut 26:6) — the rape of the concubine is described with the same term used for Israel's oppression in Egypt, a bitter inversion: Israel's oppressors are now other Israelites.</p>",
    "6": "<p><em>wāʾōḥaz bĕpîlagtî wāʾănattĕḥehā wāʾĕšallĕḥāh bĕkol-śĕdēh naḥălat yiśrāʾēl kî ʿāśû zimmāh ûnĕbālāh bĕyiśrāʾēl</em> — 'I took my concubine and cut her in pieces and sent her through all the territory of Israel's inheritance, for they committed outrage and folly in Israel.' <em>zimmāh</em> (H2154, lewdness/outrage — especially sexual crime; Lev 18:17, 19:29; Ezek 16:27) and <em>nĕbālāh</em> (H5039, folly/disgrace — the covenantal crime word from Gen 34:7, Shechem and Dinah; the act that violates covenant community) — the pairing of these two terms indicts Gibeah with the full weight of covenant-crime vocabulary. The same pairing appears in Jer 29:23 for those who commit adultery with their neighbor's wife — it is the vocabulary of the gravest social-covenant violations.</p>",
    "7": "<p><em>hinnĕkem kullĕkem bĕnê yiśrāʾēl hābû lākem dābār wāʿēṣāh hāllōm</em> — 'Look, all of you are the sons of Israel; give your verdict and counsel here.' <em>dābār wāʿēṣāh</em> (verdict and counsel) — forensic deliberative terms; <em>ʿēṣāh</em> (H6098) is the counsel sought from wisdom or elders. The Levite throws the deliberation entirely to the assembly, making himself plaintiff without offering a solution — which will prove critical, since the assembly's decisions in ch. 21 have no divine warrant.</p>",
    "8": "<p><em>wayyāqom kol-hāʿām kĕʾîš ʾeḥād lēʾmōr lōʾ nēlek ʾîš lĕʾōhŏlô wĕlōʾ-nāsûr ʾîš lĕḇêtô</em> — 'All the people rose as one man, saying: not one will go to his tent, and not one will return to his house.' The repetition of <em>kĕʾîš ʾeḥād</em> hammers the theme. The oath language (<em>lōʾ-nāsûr</em>, will not return) anticipates the oath problem in ch. 21: rash collective vows sworn in assembly will constrain Israel's options and generate further atrocity. The rhetorical pattern — unanimous declaration at an assembly — is the same structure as Ezra 10:12 (community covenanting to put away foreign wives) and Neh 8:6 (all the people answer Amen), but here it generates violence rather than reformation.</p>",
    "9": "<p><em>wĕʿattāh zeh haddābār ʾăšer naʿăśeh laggibĕʿāh bĕgôrāl ʿālâ ʿālêhā</em> — 'And now this is the thing we will do to Gibeah: we will go up against it by lot.' <em>bĕgôrāl</em> (H1486, by lot) — the lot as a decision-making mechanism is specifically associated with distributing the inheritance (Joshua 15-21; Num 26:55) and with seeking YHWH's guidance (Prov 16:33: the lot is cast into the lap but its every decision is from YHWH). Using the lot here implies (without confirming) divine guidance — but there is no explicit oracle, no Urim and Thummim invoked.</p>",
    "10": "<p><em>wĕlāqaḥnû ʿăśārāh ʾănāšîm lĕmēʾāh lĕkol šibṭê yiśrāʾēl ûmēʾāh lĕʾelep ûʾelep lĕrĕbābāh lāleket lāqaḥat ṣēdāh lāʿām</em> — a logistics verse for provisioning the army: 10% selected as supply-train. <em>ṣēdāh</em> (H6720, provision/food supply) — the same word used for the provision Jacob sends ahead to Joseph (Gen 42:25) and for Joshua's army (Josh 9:11). The detailed military organization signals a serious campaign — Israel is mobilizing as for a major external war.</p>",
    "11": "<p><em>wayyēʾāsep kol-ʾîš yiśrāʾēl ʾel-hāʿîr kĕʾîš ʾeḥād ḥăḇērîm</em> — 'So all the men of Israel gathered against the city, united as one man, allies.' <em>ḥăḇērîm</em> (H2270, bound together/allies — the root ḥbr = to bind or join) — describes the solidarity of the coalition. The word also appears in Exod 26:3 for the curtains of the tabernacle being joined together — a unity image. Three times in this chapter (vv. 1, 8, 11) Israel is called <em>kĕʾîš ʾeḥād</em>; the repetition is the narrator's way of marking the tragic irony.</p>",
    "12": "<p><em>wayyišlĕḥû šibṭê yiśrāʾēl ʾănāšîm bĕkol-šēḇeṭ binyāmîn lēʾmōr mah hārāʿāh hazzōʾt ʾăšer nihyĕtāh bākem</em> — 'The tribes of Israel sent men through all the tribe of Benjamin, saying: What is this evil that has happened among you?' <em>rāʿāh</em> (H7451, evil) — the standard covenant-violation term. The phrasing echoes the legal rhetoric of Deuteronomy 17:12 and 22:21-24 where the community is charged to purge evil (<em>bāʿar hārāʿ</em>) from their midst. The tribes are applying Deuteronomic law to a Levitical crime — the correct procedure, but Benjamin's refusal (v.13) puts the tribe outside the covenant community.</p>",
    "13": "<p><em>wĕʿattāh tĕnû ʾet-hāʾănāšîm bĕnê-ḇĕlîyaʿal ʾăšer bĕgibĕʿāh ûnĕmîtēm wĕnĕbāʾărāh rāʿāh miyyiśrāʾēl wĕlōʾ ʾābû bĕnê binyāmîn lišmōaʿ bĕqôl ʾăḥêhem bĕnê yiśrāʾēl</em> — 'Hand over the men of Belial in Gibeah so we may put them to death and purge the evil from Israel. But the Benjamites were not willing to listen to the voice of their brothers.' <em>bĕnê bĕlîyaʿal</em> (sons of Belial — H1100, literally sons of worthlessness/destructiveness; the same term applied to the Sodomite-like men in 19:22 and to Eli's sons, 1 Sam 2:12). <em>bāʿar rāʿāh</em> (purge the evil) — the identical phrase from Deut 21:21, 22:21-24 for removing covenant pollutants; the formula marks capital punishment as a community-cleansing act. Benjamin's refusal to hand over the guilty is the decisive covenant break: they choose tribal solidarity over covenant justice.</p>",
    "14": "<p><em>wayyēʾāsĕpû bĕnê-binyāmîn min-hĕʿārîm giḇĕʿātāh lāṣēʾt lammilḥāmāh ʿim-bĕnê yiśrāʾēl</em> — 'The Benjamites rallied from their cities to Gibeah to go to war against the sons of Israel.' The gathering verb <em>ʾāsap</em> (H622) is used throughout for covenant assembly (Num 11:16 for the seventy elders; Deut 33:5 for the assembly of the tribes). Here it is turned against the covenant. Gibeah becomes the Benjamin loyalists' muster point — the city of the crime becomes the fortress of defense.</p>",
    "15": "<p><em>wayyitpāqĕdû bĕnê binyāmîn bayyôm hahûʾ mēhĕʿārîm ʿĕśrîm wĕšiššāh ʾelep ʾîš šōlēp ḥāreb lĕḇad miššiḇĕʿ mēʾôt ʾîš bāḥûr</em> — 'The Benjamites numbered twenty-six thousand swordsmen from their cities, besides seven hundred chosen men.' <em>pāqad</em> (H6485, muster/number) — census language, the same root used for the wilderness musters in Numbers. The precision of the numbers (26,000 + 700 = 26,700) emphasizes Benjamin's real military capability; they are outnumbered but formidable. The 700 chosen men (<em>bāḥûr</em>, H977 — select/young warriors) echo the elite troops in other contexts (2 Sam 10:9; Jer 49:19).</p>",
    "16": "<p><em>mikkol hāʿām hazzeh šĕbāʿ mēʾôt ʾîš bāḥûr ʾiṭṭēr yad-yĕmînô kull·ô qōlēaʿ bāʾeben ʾel-haśśaʿărāh wĕlōʾ yaḥĕṭāʾ</em> — 'Seven hundred chosen men left-handed — every one could sling a stone at a hair's breadth and not miss.' <em>ʾiṭṭēr yad-yĕmînô</em> (H334, bound in his right hand = left-handed) — the same rare descriptor used for Ehud in 3:15. Bitter irony: the tribe of Benjamin (<em>ben yāmîn</em> = son of the right hand) specializes in left-handed fighters. These 700 slingers echo the 600 armed Danites of ch. 18 and the 600 Benjamin survivors of v.47. The slinger's precision (<em>lōʾ yaḥĕṭāʾ</em>, will not miss — root ḥṭʾ, which is also the word for sin/miss-the-mark) creates a wordplay: they do not miss the target but they have catastrophically missed the covenant mark.</p>",
    "17": "<p><em>wĕʾanšê yiśrāʾēl hitpāqĕdû lĕḇad mibinyāmîn ʾarbāʿ mēʾôt ʾelep ʾîš šōlēp ḥāreb kull·ô ʾanšê milḥāmāh</em> — 'The men of Israel numbered 400,000 swordsmen apart from Benjamin, all fighting men.' The coalition outnumbers Benjamin roughly 15:1. The disparity sets up the theological point of vv.21-25: Israel loses two battles despite overwhelming numbers before YHWH acts in the third. This mirrors the Exodus principle that divine deliverance is not by numbers (Deut 7:7; 1 Sam 14:6) — except here the lesson is inverted: it is not a small army YHWH is vindicating but a repentant covenant community that must acknowledge its own complicity before receiving victory.</p>",
    "18": "<p><em>wayyāqumû wayyaʿălû ḇêt-ʾēl wayyišʾălû ḇĕʾĕlōhîm wayyōʾmĕrû bĕnê yiśrāʾēl mî yaaʿăle lānû ḇarĕʾšônāh lammilḥāmāh ʿim-bĕnê binyāmîn wayyōʾmer YHWH yĕhûdāh ḇarĕʾšônāh</em> — 'They went up to Bethel and inquired of God. Judah shall go up first, YHWH said.' The inquiry verb <em>šāʾal bĕ-</em> (H7592, inquire of/through) is the same root used in 1:1 — the book's opening inquiry — and is related to the name Saul (<em>šāʾûl</em>, the one asked for). The parallel with 1:1 is exact: same question (who goes first?), same answer (Judah). But here the outcome is catastrophic defeat. The narrator is using the structural echo to show that the covenant machinery is functioning (they do inquire, YHWH does answer) but the community's underlying moral condition prevents blessing. <em>Bethel</em> (house of God) — where Jacob encountered God (Gen 28), now a site of repeated inquiry in the crisis chapters.</p>",
    "19": "<p><em>wayyāqumû bĕnê yiśrāʾēl babbōqer wayyaḥănû ʿal-giḇĕʿāh</em> — 'The sons of Israel rose up in the morning and encamped against Gibeah.' A transitional verse. The <em>babbōqer</em> (in the morning) pattern marks urgency and fresh-start energy throughout the OT (Exod 24:4; Josh 6:12 — Joshua rises early for Jericho). The morning action leads to the day's disaster (v.21 — 22,000 cut down).</p>",
    "20": "<p><em>wayyēṣĕʾû bĕnê binyāmîn miggibĕʿāh</em> — 'The Benjamites came out of Gibeah.' A transitional verse; Benjamin's forces sally from their stronghold. The movement — Israel advancing, Benjamin sallying — sets up the geography of the ambush narrative that comes in vv.29-44.</p>",
    "21": "<p><em>wayyaškîtû bĕnê binyāmîn mimmilḥāmāh ʾel-hayyôm hahûʾ ʾarbāʿāh wĕʿĕśrîm ʾālep îš lāʾāreṣ</em> — 'Benjamin struck down on that day 22,000 men of Israel to the ground.' <em>lāʾāreṣ</em> (to the ground) — the fallen-to-ground idiom for battle death. The number is staggering: 22,000 in a single day. Theologically the defeat is unresolved — Israel went with YHWH's sanction (v.18) but suffered catastrophically. The text refuses easy answers: YHWH said go; they went; they lost. The subsequent inquiries (vv.23, 27-28) show an escalating recognition that something in their own posture must change.</p>",
    "22": "<p><em>wayyitḥazzēq hāʿām ʾanšê yiśrāʾēl wayyōsipû laarōk milḥāmāh bammāqôm ʾăšer āreḵû-šām bayyôm hāriʾšôn</em> — 'The people, the men of Israel, took courage and formed up battle again in the same place as on the first day.' <em>wayyitḥazzēq</em> (H2388, they strengthened themselves/took courage — Hithpael of ḥzq) — the same root used for Ezra's strengthening himself to execute reform (Ezra 7:28) and for David's encouragement at Ziklag (1 Sam 30:6). The repetition of <em>hammāqôm... hayyôm hāriʾšôn</em> (the same place as on the first day) is important: they return to the exact formation, unchanged — the definition of foolishness (expecting different results).</p>",
    "23": "<p><em>wayyaʿălû bĕnê yiśrāʾēl wayyiḇkû lipnê YHWH ʿad-hāʿerev wayyišʾălû ḇĕYHWH lēʾmōr hăʾôsîp laggeshet lammilḥāmāh ʿim-bĕnê binyāmîn ʾāḥî wayyōmer YHWH ʿălû ʾēlāyw</em> — 'They went up and wept before YHWH until evening. They asked YHWH: shall we again draw near to battle against our brother Benjamin? YHWH said: Go up against him.' Notable shift: first inquiry (v.18) used <em>ʾĕlōhîm</em>; now they use the covenant name <em>YHWH</em>. The <em>wĕyiḇkû</em> (they wept) marks the beginning of emotional processing; but there is no fasting yet, no burnt offering — just weeping. YHWH's answer is again affirmative, yet the second battle ends with 18,000 more dead (v.25). The two losses before victory mirror the Gideon principle: YHWH strips away false confidence before he acts.</p>",
    "24": "<p><em>wayyiqrĕbû bĕnê yiśrāʾēl ʾel-bĕnê binyāmîn bayyôm haššēnî</em> — 'The sons of Israel advanced against the Benjamites on the second day.' Transitional verse. <em>qāraḇ</em> (H7126, drew near) has a cultic register (draw near to God, to the altar) as well as a military one — the dual usage here is part of the chapter's texture of inquiry and combat.</p>",
    "25": "<p><em>wayyēṣēʾ binyāmîn liḡrāʾtām miggibĕʿāh bayyôm haššēnî wayyaškîtû ḇĕḇĕnê yiśrāʾēl ʿôd šĕmônāt ʿāśār ʾelep ʾîš lāʾāreṣ kull·ô-ʾēlleh šōlĕpê ḥāreb</em> — 'Benjamin came out of Gibeah on the second day and struck down 18,000 more men of Israel — all swordsmen.' A second crushing defeat. Total Israeli casualties after two days: 40,000. The losses equal roughly 10% of the original force, numbers proportional to a major battle. The narrator's lack of theological commentary at this point (YHWH gave the order both times) is deliberate — the tension is maintained until the third inquiry (vv.26-28) resolves the theological problem by changing Israel's posture.</p>",
    "26": "<p><em>wayyaʿălû kol-bĕnê yiśrāʾēl wĕkol-hāʿām wayyāḇōʾû ḇêt-ʾēl wayyiḇkû wayyēšĕḇû šām lipnê YHWH wayyāṣûmû bayyôm hahûʾ ʿad-hāʿāreḇ wayyaʿălû ʿōlôt ûšĕlāmîm lipnê YHWH</em> — 'They came to Bethel and wept. They sat before YHWH and fasted that day until evening and offered burnt offerings and peace offerings before YHWH.' The third inquiry is preceded by the fullest worship response yet: weeping + sitting before YHWH + fasting + <em>ʿōlôt</em> (burnt offerings, complete sacrifice, total dedication) + <em>šĕlāmîm</em> (peace/fellowship offerings, communion sacrifice). The combination of burnt and peace offerings is the signature worship of the Sinai covenant (Exod 24:5) and of Solomon's dedication of the temple (1 Kgs 8:64). Israel has moved from asking (v.18) to weeping (v.23) to full liturgical prostration (v.26). The pattern mirrors the Psalms' complaint trajectory (see Ps 22, 69): the community must exhaust its own resources before YHWH responds.</p>",
    "27": "<p><em>wayyišʾălû bĕnê yiśrāʾēl ḇĕYHWH kî-šām ʾărôn bĕrît-hāʾĕlōhîm bayyāmîm hāhēm</em> — 'The sons of Israel inquired of YHWH — for the ark of the covenant of God was there in those days.' <em>ʾărôn bĕrît-hāʾĕlōhîm</em> (ark of the covenant of God) — a double-compound title combining covenant (<em>bĕrît</em>) and the generic divine name. The ark's presence is noted as providing the legitimacy of the inquiry: the portable sanctuary where YHWH's presence dwelt, normally associated with Shiloh (1 Sam 1:3; 3:3), is at Bethel at this point. The parenthetical note (vv.27-28) grounds the narrative in an archival claim about historical location.</p>",
    "28": "<p><em>wĕpînĕḥās ben-ʾelʿāzār ben-ʾahărōn ʿōmēd lĕpānāyw bayyāmîm hāhēm wayyōʾmĕrû hăʾôsîp lāṣēʾt lammilḥāmāh ʿim-bĕnê binyāmîn ʾāḥî ʾim-ʾeḥdal wayyōmer YHWH ʿălû kî māḥār ʾettĕnnennû bĕyādekā</em> — 'Phinehas son of Eleazar son of Aaron was ministering before it. They said: shall we go out once more or stop? YHWH said: Go up, for tomorrow I will give him into your hand.' The Phinehas identification (H6372, grandson of Aaron, Num 25:7 — the zealous priest who executed the Baal-Peor offenders) is a chronological anchor: if Phinehas is still alive and ministering, the Gibeah episode is placed in the early judges period, not late. This is the narrator's insertion of archival data to prevent the reader from assuming the epilogue events (chs. 17-21) are chronologically after the main narratives. The divine promise <em>māḥār ʾettĕnnennû bĕyādekā</em> (tomorrow I will give him into your hand) is the holy-war oracle formula used by YHWH at Jericho (Josh 6:2: <em>nātattî bĕyādekā</em>) and in the Deborah narrative (4:7). Its appearance here signals that YHWH's patience with the inquiry process has been rewarded with covenant-war authorization.</p>",
    "29": "<p><em>wayyāśem yiśrāʾēl ʾōrĕḇîm ʾal-giḇĕʿāh sāḇîḇ</em> — 'Israel set ambushers around Gibeah.' <em>ʾōrĕḇîm</em> (H693, ambushers — the verb ʾāraḇ, to lie in wait) — the identical ambush strategy as Joshua 8:2, 4 at Ai, where YHWH commanded the ambush against the same city type: a small fortified stronghold that lured Israel out and then was taken from the rear. The Ai-parallel is deliberate: the battle of Gibeah mirrors the capture of Ai structurally — feigned retreat, ambush, city burning, smoke signal. This positions the civil war as a reversal-application of conquest warfare: the tools YHWH gave Israel for taking Canaan are now used against a Canaanized Israelite city.</p>",
    "30": "<p><em>wayyaʿălû bĕnê yiśrāʾēl ʾel-bĕnê binyāmîn bayyôm haššĕlîšî wayyaʿarĕkû ʾel-giḇĕʿāh kĕpaʿam bĕpaʿam</em> — 'The sons of Israel went up against the Benjamites on the third day and deployed as before.' <em>kĕpaʿam bĕpaʿam</em> (as time upon time/as before) — the idiom of repeated action (cf. Num 24:1; 1 Sam 3:10). The identical deployment masks the ambush — the same tactic used at Ai (Josh 8:5-6 — the ambushers hide while the main force feigns retreat).</p>",
    "31": "<p><em>wayyēṣĕʾû bĕnê binyāmîn liḡrāʾt hāʿām nittĕqû min-hāʿîr wayyāḥēllû lĕhakôt ḥălālîm kĕpaʿam bĕpaʿam</em> — 'The Benjamites came out and were lured away from the city. They began to strike down some and kill them as before.' <em>nittĕqû</em> (H5423, were drawn/lured away — Niphal of nāṯaq, to tear away, draw away) — the passive form emphasizes Benjamin's lack of agency; they were drawn into the ambush, not the other way around. The <em>ḥălālîm</em> (H2491, the slain — those pierced/wounded) — a poetic/military term for battlefield dead.</p>",
    "32": "<p><em>wayyōʾmĕrû bĕnê binyāmîn nikkîm hēm lĕpānênû kĕbarĕʾšônāh wĕḇĕnê yiśrāʾēl ʾāmĕrû nānûsāh wĕnitteqnûhû min-hāʿîr ʾel-hammĕsillôt</em> — 'The Benjamites said: they are falling before us as before! But Israel had said: let us flee and draw them away from the city onto the roads.' The narrator reveals the hidden strategy — Israel's words (<em>ʾāmĕrû</em>) are placed against Benjamin's words (<em>wayyōʾmĕrû</em>) in the same verse, showing the gap between what Benjamin perceives and what is actually happening. <em>nānûsāh</em> (let us flee) — the feigned retreat, the same tactical deception as at Ai (Josh 8:15-16 — Joshua's army fled toward the wilderness). Deception in warfare is not condemned in the OT when used against those who have forfeited covenant standing.</p>",
    "33": "<p><em>wĕkol ʾîš yiśrāʾēl qāmû mimmĕqōmô wayyaʿarĕkû bĕḇaʿal tāmār wĕʾōrēḇ yiśrāʾēl mĕgāraʿô mimmĕqōmô mimaʿărēh-giḇaʿ</em> — 'All the men of Israel rose from their place and formed up at Baal-tamar, and the Israelite ambush burst forth from its place at Maare-gibeah.' The coordinated maneuver: the main force wheels at Baal-tamar while the ambushers at Maare-gibeah emerge. <em>mĕgāraʿô</em> (from its pastureland/open ground — H4629) — a hapax in this sense; the ambushers burst out from the meadow. The precision of place names (Baal-tamar, Maare-gibeah) is unusual for Judges, suggesting the narrator is drawing on a detailed source account of the battle.</p>",
    "34": "<p><em>wayyāḇōʾû miggibĕʿāh ʿăśeret ʾălāpîm ʾîš bāḥûr mikkol yiśrāʾēl ûmilḥāmāh kāḇēdāh wĕhēm lōʾ yādĕʿû kî-nōgeaʿ ʿălêhem hārāʿāh</em> — 'Ten thousand chosen men from all Israel struck at Gibeah itself, and the battle was heavy. But they did not know that disaster was coming upon them.' <em>lōʾ yādĕʿû</em> (they did not know) — the Judges phrase of fatal ignorance (3:2 — Israel did not know war; 16:20 — Samson did not know YHWH had departed). Benjamin's commanders are now in the same structural position as Samson: unaware that the power that sustained them has withdrawn. <em>nōgeaʿ</em> (H5060, touching/striking — coming upon them) — the same root used for the plague touching Israel (Exod 12:13).</p>",
    "35": "<p><em>wayyiggōp YHWH ʾet-binyāmîn lipnê yiśrāʾēl wayyaškîtû bĕnê yiśrāʾēl bĕbinyāmîn bayyôm hahûʾ ʿĕśrîm wĕḥāmiššāh ʾelep ûmēʾāh ʾîš kull·ô-ʾēlleh šōlĕpê ḥāreb</em> — 'YHWH struck down Benjamin before Israel. The sons of Israel destroyed 25,100 Benjamite swordsmen that day.' <em>wayyiggōp YHWH</em> (H5062, YHWH struck/smote — Qal of nāgap, to strike, especially of divine plague-blow) — the first explicit statement of YHWH's active agency in this chapter. He is named in the inquiry responses but his smiting is not announced until v.35, after the full liturgical preparation of v.26. The verb nāgap is used of YHWH striking Egypt (Exod 12:23, 27), striking the ark-bearers (1 Sam 4:3), and striking Uzzah (2 Sam 6:7) — it is the divine strike-verb for judgment executed directly by YHWH.</p>",
    "36": "<p><em>wayyirʾû bĕnê binyāmîn kî niggāpû wĕyittĕnû ʾanšê yiśrāʾēl mākôm lĕbinyāmîn kî bāṭĕḥû ʾel-hāʾōrēḇ ʾăšer śāmû ʾel-giḇĕʿāh</em> — 'The Benjamites saw they were beaten, for the men of Israel gave ground relying on the ambush set at Gibeah.' A retrospective explanation inserted into the battle narrative — the narrator provides the ambush's mechanism. <em>bāṭĕḥû</em> (H982, they trusted/relied on — bāṭaḥ, the standard trust-confidence word of the Psalms, e.g., Ps 22:4-5) — their trust was in the ambush, a military strategy. The placement of this trust-word in a military context echoes Ps 20:7 (some trust in chariots) and 1 Sam 17:45 (Goliath trusts in sword and spear).</p>",
    "37": "<p><em>wayyĕmahēr hāʾōrēḇ wayyipšĕṭû ʾel-giḇĕʿāh wayyēlek hāʾōrēḇ wayyak ʾet kol-hāʿîr leḥepê ḥāreb</em> — 'The ambushers rushed and spread out through Gibeah; the ambush struck the whole city with the edge of the sword.' <em>wayyĕmahēr</em> (H4116, rushed/made haste — māhar) — the speed of the ambush's response to the signal. <em>leḥepê ḥāreb</em> (H6310+H2719, edge/mouth of the sword) — literally 'to the mouth of the sword,' a standard formula for total slaughter (Gen 34:26; Josh 6:21; 8:24). The same language is used for Jericho's destruction.</p>",
    "38": "<p><em>wĕhammoʿēd hāyāh lĕʾanšê yiśrāʾēl ʿim hāʾōrēḇ lĕharḇôt maśʾat heʿāšān min-hāʿîr</em> — 'The prearranged signal between the men of Israel and the ambush was that they should send up a great cloud of smoke from the city.' <em>moʿēd</em> (H4150, appointed sign/meeting — the same word as mōʿēd for the Tent of Meeting/appointed feast; here meaning a pre-arranged signal). The smoke signal is the analogue to Joshua 8:19-20, where the smoke over Ai signals the ambushers to close the trap. The use of <em>moʿēd</em> (a sacred-calendar word) for a military signal is not theologically loaded here, but the lexical choice points to the dual register of this word throughout the OT.</p>",
    "39": "<p><em>wĕhāpōk ʾanšê yiśrāʾēl bammilḥāmāh ûḇinyāmîn heḥēl lĕhakôt ḥălālîm bĕʾanšê yiśrāʾēl kĕšĕlōšîm ʾîš</em> — 'When the Israelites turned in battle and Benjamin began to strike down some thirty men of Israel.' A transitional verse describing the feigned retreat phase. The specific number 'about thirty' (<em>kĕšĕlōšîm ʾîš</em>) signals Benjamin's overconfidence — they take thirty when they expected to rout thousands.</p>",
    "40": "<p><em>wĕhammaśśĕʾt heḥēllāh laʿălôt min-hāʿîr tîmĕrat ʿāšān wĕyipen binyāmîn ʾaḥărāyw wĕhinnēh ʾālāh kĕlîl-hāʿîr haššāmāyimāh</em> — 'The pillar of smoke began to rise from the city; the Benjamites looked back — the whole city was ascending in smoke to the heavens.' <em>tîmĕrat ʿāšān</em> (pillar of smoke — H8490+H6227) — the same phrase used in Joel 2:30 for the cosmic signs of the Day of YHWH and in Song 3:6 for the bride's procession 'coming up like a column of smoke.' The visual image of Gibeah ascending in smoke is the mirror of Sodom (Gen 19:28: the smoke of the land went up like the smoke of a furnace) — the Sodom-parallel the narrator established in ch. 19 is now completed visually.</p>",
    "41": "<p><em>wĕʾanšê yiśrāʾēl hāpākû ûḇinyāmîn neḥĕpaz kî rāʾāh kî nāgĕʿāh ʿālāyw hārāʿāh</em> — 'The Israelites turned and the Benjamites were terrified — they saw that disaster had come upon them.' <em>neḥĕpaz</em> (H926, were terrified/dismayed — the Niphal of bāhal, to terrify, be dismayed; cf. Isa 21:3, Ps 6:11) — a strong psychological-fear term. <em>rāʿāh</em> (evil/disaster) — the same word used for Benjamin's evil in v.12. What they refused to purge from their midst now returns upon them.</p>",
    "42": "<p><em>wayyipnû lipnê ʾanšê yiśrāʾēl ʾel-derek hammidbār ûmilḥāmāh hidbîqattu ûʾăšer min-hĕʿārîm maśḥîtîm ʾôtô bĕtôkô</em> — 'They turned before the men of Israel toward the desert, but the battle caught up with them; and those who came out of the cities destroyed them in the middle.' <em>hidbîqattu</em> (H1692, stuck to/pursued relentlessly — dāḇaq, the same root as Ruth 1:14, Ruth cleaving to Naomi; and Deut 4:4, clinging to YHWH) — the pursue-and-cling root is here used for a battle catching up with fleeing soldiers, a grim reversal of the covenant-loyalty term.</p>",
    "43": "<p><em>kilĕlû ʾet-binyāmîn rādĕpû minnûḥāh haddĕrîsûhû nōkaḥ giḇĕʿāh mizrāḥ šāmšāh</em> — 'They surrounded Benjamin, pursued from Menuha, trampled them toward the east of Gibeah as the sun rose.' <em>kilĕlû... rādĕpû... haddĕrîsûhû</em> (surrounded... pursued... trampled) — a poetic triplet of destruction verbs. The triplet recalls the Exodus pattern: Egypt surrounded Israel, pursued, then was overwhelmed (Exod 14:23-28). Here Israel applies the pursuit-and-trampling verbs to their own kindred.</p>",
    "44": "<p><em>wayyippĕlû mibinyāmîn šĕmônāt ʿāśār ʾelep ʾîš kull·ô-ʾēlleh ʾanšê ḥāyil</em> — 'Eighteen thousand from Benjamin fell — all of them men of valor.' <em>ʾanšê ḥāyil</em> (H376+H2428, men of valor/capability) — the honorific used throughout Judges and Ruth for elite fighters. The narrator honors even the fallen enemies with their warrior-dignity designation. The running total: 18,000 here, 5,000 in v.45, 2,000 more, total 25,100 (v.35).</p>",
    "45": "<p><em>wayyipnû wayyānusû hammidbārāh ʾel-selaʿ hārimôn wayyĕʿōllĕhû bammĕsillôt ḥămiššet ʾălāpîm ʾîš wayyaddĕbîqû ʾaḥărāyw ʿad giḇĕʿāh ûwayyakû mimmennû ʾalpayim ʾîš</em> — 'They turned and fled toward the rock of Rimmon; 5,000 were cut down on the roads; 2,000 more were pursued to Gibeah.' The rock of Rimmon (<em>selaʿ hārimôn</em>) becomes the refuge for the 600 survivors (v.47). <em>Rimmon</em> (H7417, pomegranate — the same word as the pomegranate decorations on the temple pillars, 1 Kgs 7:18) — a geographical name that carries no special theological resonance here, but the cave-refuge of 600 men will become the seed of Benjamin's survival in ch. 21.</p>",
    "46": "<p><em>wayyĕhî kol-hannoplîm mibinyāmîn ʿĕśrîm wĕḥāmiššāh ʾelep ʾîš šōlēp ḥāreb bayyôm hahûʾ kull·ô-ʾēlleh ʾanšê ḥāyil</em> — 'All who fell from Benjamin on that day totaled 25,000 swordsmen — all men of valor.' The summary verse closes the battle account with the same honorific (<em>ʾanšê ḥāyil</em>) for the fallen. The precision of the total (25,000, matching v.35's 25,100 count) and the repeated honorific signals that the narrator is being careful to neither dehumanize Benjamin nor glorify their defeat.</p>",
    "47": "<p><em>wayyipnû wayyānusû hammidbārāh ʾel-selaʿ hārimôn šĕš-mēʾôt ʾîš wayyēšĕḇû bĕselaʿ-rimôn ʾarbāʿāh ḥŏdāšîm</em> — 'Six hundred men fled to the rock of Rimmon and stayed there for four months.' <em>šĕš-mēʾôt</em> (600 men) — the number echoes the 600 Danites of 18:11 and, more significantly, the 600 who fled with David at Ziklag (1 Sam 27:2 — David's core fighting force). The four months of exile at Rimmon creates a narrative pause before ch. 21's resolution attempts. The number 600 will drive the arithmetic of ch. 21: 400 Jabesh-gilead virgins (v.12) are insufficient, necessitating the Shiloh plan.</p>",
    "48": "<p><em>wĕʾanšê yiśrāʾēl šābû ʾel-bĕnê binyāmîn wayyakkûm leḥepê ḥāreb mēʿîr mĕtōm ʿad-bĕhēmāh ʿad kol-hannimṣāʾ gam kol-hĕʿārîm hannimṣāʾôt śārepû bāʾēš</em> — 'The men of Israel turned against the Benjamites and put them to the sword — men, animals, and all found — and all the cities they found they burned with fire.' The ḥērem-like totality of this destruction — <em>mēʿîr mĕtōm ʿad-bĕhēmāh</em> (from the cities: people to animals) — echoes the ḥērem formulas of Joshua 6:21 (Jericho: people, animals, everything) and 1 Sam 15:3 (Saul's charge to destroy Amalek totally). There is no divine command for this total destruction; Israel acts on its own authority, and the consequences (ch. 21's wife crisis) follow from the totality of their retribution.</p>"
  },
  "21": {
    "1": "<p><em>wĕʾîš yiśrāʾēl nišbaʿ bammizpāh lēʾmōr ʾîš mimmennû lōʾ-yittēn bittô lĕbinyāmîn lĕʾiššāh</em> — 'Now the men of Israel had sworn at Mizpah: no man among us will give his daughter to Benjamin in marriage.' The oath (<em>nišbaʿ</em>, H7650, swore — the Niphal) is the first word of ch. 21 but chronologically precedes the assembly in ch. 20. The narrator inserts the oath here to frame the entire resolution crisis: every solution they attempt in ch. 21 is constrained by this vow. The oath structure echoes Jephthah's rash vow (11:30-31) and the oath pattern of Saul in 1 Sam 14:24-45 — hasty assembly oaths that create unforeseen binding constraints.</p>",
    "2": "<p><em>wayyāḇōʾ hāʿām ḇêt-ʾēl wayyēšĕḇû šām ʿad-hāʿerev lipnê hāʾĕlōhîm wayyišʾû qôlām wayyiḇkû ḇĕkî gāḏôl</em> — 'The people came to Bethel and sat before God until evening, lifting their voices and weeping with great weeping.' <em>ḇĕkî gāḏôl</em> (H1065+H1419, great weeping — the superlative construction) — the same phrase used for Jacob's weeping when he reveals himself to Joseph (Gen 45:2) and Joseph's weeping at Jacob's death (Gen 50:1). The communal grief is genuine: they have destroyed their own tribe and now face an irreversible oath. <em>lipnê hāʾĕlōhîm</em> (before God) — the Elohim register again (as in 20:2); the narrator distinguishes levels of divine address.</p>",
    "3": "<p><em>wayyōʾmĕrû lāmmāh YHWH ʾĕlōhê yiśrāʾēl hāyĕtāh zōʾt bĕyiśrāʾēl lehippāqēd hayyôm miyyiśrāʾēl šēḇeṭ ʾeḥād</em> — 'They said: O YHWH, God of Israel, why has this happened — that today one tribe should be missing from Israel?' The shift from <em>hāʾĕlōhîm</em> (v.2) to <em>YHWH ʾĕlōhê yiśrāʾēl</em> (v.3) in address mirrors ch. 20's progressive approach to the covenant name. <em>lehippāqēd</em> (H6485, that one should be missed/lacking — Niphal: to be numbered, then to be found missing from the count) — the same root used for the wilderness census (Num 1-4); when Israel is numbered, a missing tribe is a covenant gap. The lament form (why, YHWH?) echoes Ps 22:1, Ps 88:14 — the community is modeling the psalmic address of distress.</p>",
    "4": "<p><em>wayyĕhî mimmoḥorāt wayyaškîmû hāʿām wayyiḇnû-šām mizbēăḥ wayyaʿălû ʿōlôt ûšĕlāmîm</em> — 'The next morning the people rose early and built an altar there, offering burnt and peace offerings.' <em>mimmoḥorāt</em> (H4283, on the next day) — the early-morning pattern of devotion (cf. 20:19). The altar-building and dual sacrifice (<em>ʿōlôt ûšĕlāmîm</em>) repeat the full worship of 20:26; the community re-enacts its priestly response before seeking a solution. The altar at Bethel is established without divine command — it is the community's spontaneous act of worship-before-decision, which the text records without censure.</p>",
    "5": "<p><em>wayyōʾmĕrû bĕnê yiśrāʾēl mî ʾăšer lōʾ-ʿālāh baqqāhāl mikkol šibṭê yiśrāʾēl ʾel-YHWH kî hašĕḇûʿāh hağĕdōlāh hāyĕtāh lāʾăšer lōʾ-ʿālāh ʾel-YHWH hammiṣpāh lēʾmōr mwt yûmāt</em> — 'Who of all the tribes of Israel did not come to the assembly before YHWH? For there was a great oath: anyone who did not come up to YHWH at Mizpah shall surely be put to death.' <em>hašĕḇûʿāh hağĕdōlāh</em> (the great oath) — a solemn communal vow with the penalty of death. The oath now creates a second problem: Jabesh-gilead's absence from the assembly makes them oath-violators subject to the death penalty, which then provides the rationale for the ch. 21 massacre — a cascade of covenant mechanisms producing atrocity.</p>",
    "6": "<p><em>wayyinnāḥămû bĕnê yiśrāʾēl ʾel-binyāmîn ʾāḥîw wayyōʾmĕrû niggĕraʿ hayyôm šēḇeṭ ʾeḥād miyyiśrāʾēl</em> — 'The sons of Israel had compassion for their brother Benjamin and said: one tribe is cut off from Israel today.' <em>wayyinnāḥămû</em> (H5162, had compassion/were consoled — Niphal of nāḥam, the root that means both to comfort and to repent/relent) — the same root used for YHWH's relenting in Exod 32:14 (after the golden calf), Jer 26:19, and throughout the prophets for divine repentance. Here it is Israel's emotional response: they feel regret over what they have done. <em>nāḥam</em> is a deeply ambivalent verb: it can mean grief over a past action, consolation for a present loss, or decision to change course. Israel experiences all three meanings simultaneously.</p>",
    "7": "<p><em>mah-naʿăśeh lāhem lannôtārîm lĕnāšîm waʾănaḥnû nišbaʿnû bĕYHWH lĕḇiltî tēt-lāhem mibbĕnōtênû lĕnāšîm</em> — 'What shall we do for wives for those who remain, since we swore by YHWH that we will not give them our daughters as wives?' The dilemma is stated with rhetorical precision: the two constraints (provide wives; do not break the Mizpah oath) are placed in direct collision. <em>nišbaʿnû bĕYHWH</em> (we swore by YHWH) — invoking the divine name in an oath makes it inviolable (Lev 19:12; Deut 23:21-23: what comes from your lips you must perform). The oath's inviolability is the pressure that generates the Jabesh-gilead and Shiloh solutions.</p>",
    "8": "<p><em>wayyōʾmĕrû mî ʾeḥād miššibṭê yiśrāʾēl ʾăšer lōʾ-ʿālāh ʾel-YHWH hammiṣpāh wayhinnēh lōʾ-bāʾ ʾîš ʾel-hammahăneh miyyāḇêš gilʿād ʾel-haqqāhāl</em> — 'They said: who of the tribes of Israel did not come to YHWH at Mizpah? No one from Jabesh-gilead had come.' The discovery of Jabesh-gilead's absence is presented as a rhetorical finding, not a pre-planned maneuver. <em>Jabesh-gilead</em> (H3003, from the east bank of the Jordan) — a city that will later be the site of intense loyalty to Saul (1 Sam 31:11-13: the Jabesh-gileadites retrieve Saul's body from Beth-shan), suggesting a deep historical link between Jabesh-gilead and Benjamin/Saul established partly through this episode.</p>",
    "9": "<p><em>wayyitpāqēd hāʿām wĕhinnēh ʾên-šām ʾîš miyyôšĕḇê yāḇēš gilʿād</em> — 'For when the people were mustered, there was not a man there from the inhabitants of Jabesh-gilead.' <em>wayyitpāqēd</em> (H6485, was mustered/numbered) — the census verb completing the forensic inquiry of v.5. The absence is verified by the count, not by accusation. The missing-from-the-count now becomes missing-from-the-land.</p>",
    "10": "<p><em>wayyišlĕḥû šām hāʿēdāh šĕnêm ʿāśār ʾelep ʾîš mibbenê heḥāyil wayyĕṣawwû ʾôtām lēʾmōr lĕkû wahakkîtû ʾet-yôšĕḇê yāḇēš gilʿād leḥepê ḥāreb wĕhannāšîm wĕhattap</em> — 'The congregation sent 12,000 warriors with orders: go and kill the inhabitants of Jabesh-gilead with the edge of the sword, including the women and children.' The scale (12,000 men) and the phrasing of the command (<em>leḥepê ḥāreb</em>, by the mouth of the sword) mirror the ḥērem formulas of Joshua. Israel is applying holy-war destruction to an Israelite city — the logical endpoint of the internal fragmentation that began at the opening of the book (1:1).</p>",
    "11": "<p><em>wĕzeh haddābār ʾăšer taʿăśû kol-zākār wĕkol-ʾiššāh yōdaʿat miškab-zākār taḥărîmû</em> — 'This is what you shall do: utterly destroy every male and every woman who has had sexual relations with a man.' <em>taḥărîmû</em> (H2763, devote to destruction — Hiphil of ḥāram, the ḥērem root) — the technical term for the Canaanite destruction command (Josh 6:17; Deut 7:2; 1 Sam 15:3). Applying ḥērem to an Israelite city is unprecedented and signals the total collapse of the covenant boundary between Israel and Canaan — Israel has become its own conquered enemy. <em>yōdaʿat miškab-zākār</em> (who has known the lying of a man — the Mosaic purity formula from Num 31:17-18, applied after Midian) — the criteria for sparing Jabesh-gilead virgins exactly match Moses's command after the Midianite war, another sign of the book's progressive deterioration into its own origins.</p>",
    "12": "<p><em>wayyimṣĕʾû miyyôšĕḇê yāḇēš gilʿād ʾarbāʿ mēʾôt naʿărāh bĕtûlāh ʾăšer lōʾ-yādĕʿāh ʾîš lĕmiškab zākār</em> — 'They found four hundred young virgins among the inhabitants of Jabesh-gilead who had not known a man.' <em>bĕtûlāh</em> (H1330, virgin/young woman — the specific term for a woman who has not had sexual relations, distinct from ʿalmāh which emphasizes youth) — the legal precision matters: these women are eligible under the purity criteria. The number 400 is critical: 600 survivors (20:47) minus 400 wives = 200 men still without wives, setting up the second crisis.</p>",
    "13": "<p><em>wayyišlĕḥû kol-hāʿēdāh wayyĕdabbĕrû ʾel-bĕnê binyāmîn ʾăšer bĕselaʿ-hārimôn wayyiqrĕʾû lāhem šālôm</em> — 'The whole congregation sent and called to the Benjamites at the rock of Rimmon in peace.' <em>wayyiqrĕʾû lāhem šālôm</em> (called to them in peace) — the diplomatic overture using <em>šālôm</em> (H7965, peace/wholeness). The same formula appears when Joshua's spies send word to Rahab (Josh 2:21) and in the covenant-making gestures throughout the Hebrew Bible. The community that nearly destroyed Benjamin now extends šālôm — but šālôm without structural repair (the wife problem is still unsolved) is premature.</p>",
    "14": "<p><em>wayyāšob binyāmîn bāʿēt hahîʾ wayyittĕnû lāhem hannāšîm ʾăšer ḥiyyû mibbĕnôt yāḇēš gilʿād wĕlōʾ-māṣĕʾû lāhem kēn</em> — 'Benjamin returned at that time. They were given the women spared from Jabesh-gilead as wives. But there were not enough.' <em>wĕlōʾ-māṣĕʾû lāhem kēn</em> (they did not find enough for them) — the arithmetic gap: 400 women for 600 men. The word <em>kēn</em> (H3651, thus/sufficient) creates the transition: the Jabesh-gilead solution falls short, requiring the Shiloh plan.</p>",
    "15": "<p><em>wĕhāʿām niḥam lĕbinyāmîn kî-ʿāśāh YHWH pereṣ bĕšibṭê yiśrāʾēl</em> — 'The people had compassion for Benjamin, for YHWH had made a gap in the tribes of Israel.' <em>niḥam</em> (H5162, had compassion/relented) — the nāḥam root again (cf. v.6). <em>YHWH ʿāśāh pereṣ</em> (YHWH made a gap/breach — H6556, pereṣ from pāraṣ, to break through) — the divine agency is acknowledged: the gap in the tribes is attributed to YHWH. This is not a distancing move but a theological affirmation: the outcome of the war, including the near-extinction of Benjamin, was within YHWH's providential purpose. The same root pāraṣ is used for YHWH breaking through at Baal-perazim (2 Sam 5:20: <em>YHWH pāraṣ ʿōyĕḇay</em>) and for the infant's breakthrough at birth (Gen 38:29: <em>mah-pāraṣtā ʿālêkā pāreṣ</em>, hence the name Perez).</p>",
    "16": "<p><em>wayyōʾmĕrû ziqĕnê hāʿēdāh mah naʿăśeh lannôtārîm lĕnāšîm kî-nišmĕdāh mibinyāmîn ʾiššāh</em> — 'The elders of the congregation said: what shall we do for wives for those who are left, since the women of Benjamin have been destroyed?' The elders (<em>ziqĕnê hāʿēdāh</em>, H2205+H5712, elders of the congregation) — the formal leadership structure. <em>nišmĕdāh</em> (H8045, has been destroyed/annihilated — Niphal of šāmad, used for the destruction of nations in Deut 9:3; Josh 7:12) — the verb for the total destruction of enemies is applied to Israelite women. The elders acknowledge the consequence of their own military action.</p>",
    "17": "<p><em>wayyōʾmĕrû yĕruššat pĕlêṭāh lĕbinyāmîn wĕlōʾ-yimmāḥeh šēḇeṭ miyyiśrāʾēl</em> — 'There must be an inheritance for the escaped remnant of Benjamin, so that a tribe may not be wiped out from Israel.' <em>yĕruššāh</em> (H3425, inheritance/possession — from yāraš, to inherit/possess) — the covenant-inheritance term; Benjamin must have its <em>yĕruššāh</em> to maintain its place in the covenant structure. <em>pĕlêṭāh</em> (H6413, escaped remnant/survivors — from pālaṭ, to escape) — the term for the surviving remnant of judgment (Isa 10:20; Ezra 9:8, 13). The language of remnant-preservation for Benjamin anticipates the theological vocabulary of the prophets: even in judgment, a <em>pĕlêṭāh</em> survives, because the covenant purposes require it.</p>",
    "18": "<p><em>waʾănaḥnû lōʾ nûkal lātēt lāhem nāšîm mibběnōtênû kî-nišbĕʿû bĕnê yiśrāʾēl lēʾmōr ʾārûr nōtēn ʾiššāh lĕbinyāmîn</em> — 'But we cannot give them wives from our daughters, for the sons of Israel swore: cursed is anyone who gives a wife to Benjamin.' <em>ʾārûr</em> (H779, cursed — the Qal passive participle of ʾārar, used in the covenant curses of Deut 27-28, e.g., Deut 27:15-26: twelve curse-formulas beginning with <em>ʾārûr</em>) — the oath is not just a social agreement but a covenant-curse invocation. Breaking it would bring the Deuteronomic curse upon the oath-breaker. The community has locked itself inside a self-constructed curse-framework.</p>",
    "19": "<p><em>wayyōʾmĕrû hinnēh ḥag-YHWH bĕšîlōh miyyāmîm yāmîmāh ʾăšer mişṣĕpônāh lĕḇêt-ʾēl mizrĕḥāh haššemšāh ûminnegeḇ lĕ-lĕḇônāh</em> — 'They said: there is a yearly festival of YHWH at Shiloh, north of Bethel, east of the road from Bethel to Shechem, and south of Lebonah.' <em>ḥag-YHWH</em> (H2282+H3068, feast of YHWH) — the technical term for the three major pilgrimage feasts (Exod 23:14-17: Unleavened Bread, Harvest/Weeks, Ingathering/Booths). The feast at Shiloh is almost certainly <em>Sukkot</em> (Booths/Tabernacles), associated with dancing and celebration (Ps 149:3; Ps 150:4). The precise geographical directions given for Shiloh (north of Bethel, east of the road) have the character of official geographic notation — the narrator is being precise because Shiloh is the legitimate sanctuary site (Josh 18:1; 1 Sam 1:3).</p>",
    "20": "<p><em>wayyĕṣawwû ʾet-bĕnê binyāmîn lēʾmōr lĕkû waʾăraḇtem bakkeramîm</em> — 'They commanded the Benjamites: go and lie in wait in the vineyards.' <em>waʾăraḇtem</em> (H693, lie in wait/ambush — the same <em>ʾāraḇ</em> root used for Israel's ambush in 20:29) — the ambush vocabulary from the civil war is now repurposed for abduction at a sacred festival. The strategic counsel is given by the elders to enable what the narrative presents as a legal workaround: they technically do not give their daughters, so the oath is not violated, but they facilitate the seizure. The moral logic is casuistry of the worst kind.</p>",
    "21": "<p><em>ûrĕʾîtem wĕhinnēh ʾim-yēṣĕʾû bĕnôt šîlōh lĕḥwl bamḥōlôt ûṣĕʾtem min-hakkeramîm waḥtaptem lākem ʾîš ʾiššĕtô mibbĕnôt šîlōh wahalaktem ʾereṣ binyāmîn</em> — 'Watch, and when the daughters of Shiloh come out to dance in the dances, come out of the vineyards — each man seize his wife from the daughters of Shiloh and go to Benjamin.' <em>waḥtaptem</em> (H2414, seize/snatch — ḥāṭap, a verb used rarely; elsewhere for predatory seizing) — a violent abduction verb. <em>lĕḥwl bamḥōlôt</em> (to dance in the dances — ḥûl/ḥôl in the dance circles, used in Ps 149:3 and Jer 31:13 for communal celebration dance) — the daughters of Shiloh are seized from a sacred festival, a violation compounded by its sacred setting. <em>ḥāṭap</em> does not appear in Deut 24 (laws on marriage), signaling this is outside normal covenantal procedure.</p>",
    "22": "<p><em>wĕhāyāh kî-yāḇōʾû ʾăḇôtām ʾô ʾăḥêhem lārîḇ ʾēlênû wĕʾāmarnû ʾălêhem ḥānnûnû ʾôtām kî lōʾ lāqaḥnû ʾîš ʾiššetô bammilḥāmāh kî-lōʾ ʾattem nĕtatttem lāhem kĕʿēt tiʾšāmû</em> — 'When their fathers or brothers come to us to complain, we will say: grant them to us as a gracious act, because we did not take each man a wife in battle; you did not give them, so you are not guilty.' <em>ḥānnûnû ʾôtām</em> (be gracious to them — Qal imperative of ḥānan, the root of grace/favor, cf. Ps 123:3: <em>ḥānnênû YHWH ḥānnênû</em>) — the appeal for grace toward Benjamin uses the vocabulary of prayer addressed to YHWH. The legal argument (you did not give, therefore you are not oath-bound) is technically correct but morally hollow: the elders are using a legal loophole to rationalize mass abduction.</p>",
    "23": "<p><em>wayyaʿăśû kēn bĕnê binyāmîn wayyiśśĕʾû nāšîm lĕmispārām min-hammĕḥōlĕlôt ʾăšer gāzālû wayyēlĕkû wayyāšûḇû ʾel-naḥălātām wayyiḇnû ʾet-hĕʿārîm wayyēšĕḇû bāhem</em> — 'The Benjamites did so. They seized wives for each of them from the dancers, went back to their territory, rebuilt the cities, and lived in them.' <em>gāzālû</em> (H1497, they seized/stole — gāzal, to tear away, the same root as Micah's idols stolen in 18:24 and the vocabulary of robbery in Lev 19:13; Prov 22:22) — the narrator uses the robbery verb rather than the marriage verb. The rebuilding of the cities (<em>wayyiḇnû ʾet-hĕʿārîm</em>) ends the account on a note of restoration, but without divine endorsement or covenant ceremony. Benjamin reconstitutes itself by theft from a sacred festival.</p>",
    "24": "<p><em>wayyēlĕkû miššām bĕnê yiśrāʾēl bāʿēt hahîʾ ʾîš lĕšibṭô ûlĕmišpaḥtô wayyēṣĕʾû miššām ʾîš lĕnaḥălātô</em> — 'At that time the sons of Israel departed, each to his tribe and family, each going out to his inheritance.' <em>ʾîš lĕnaḥălātô</em> (each to his inheritance) — the verse ends with the covenant-inheritance term, mirroring the distribution language of Joshua 13-21. The tribes return to their allotted territories: the covenant structure formally reconstitutes itself, but the method of Benjamin's reconstitution (massacre + abduction) lies beneath this ordered dispersal.</p>",
    "25": "<p><em>bayyāmîm hāhēm ʾên melek bĕyiśrāʾēl ʾîš hayyāšār bĕʿênāyw yaʿăśeh</em> — 'In those days there was no king in Israel. Everyone did what was right in his own eyes.' The book's closing refrain and final verdict. <em>ʾên melek bĕyiśrāʾēl</em> (no king in Israel) — the positive statement of the book's central theological diagnosis. Judges was written retrospectively from the monarchy period; the refrain functions as both explanation (why all this chaos happened) and anticipation (what was needed). <em>hayyāšār bĕʿênāyw</em> (what was right in his own eyes — H3477+H5869, rightness in his eyes) — contrasted with Deuteronomy's standard: do what is right in the eyes of YHWH (<em>hayyāšār bĕʿênê YHWH</em>, Deut 12:25; 13:18; 21:9). The substitution of <em>ʿênāyw</em> (his own eyes) for <em>ʿênê YHWH</em> (eyes of YHWH) is the anatomy of the book's failure: private judgment substituted for covenant law. The closing verse of Judges is the OT's most compressed statement of the problem that the messianic hope answers — the need for a king who embodies the will of YHWH and whose rule aligns human action with divine righteousness.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'judges')
    merge_comm(existing, JUDGES)
    save_comm('mkt-original', 'judges', existing)

    import json as _json
    il = _json.load(open(ROOT / 'data' / 'interlinear' / 'judges.json'))
    all_ok = True
    for ch in [20, 21]:
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(existing.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(existing.get(ck,{}))} verses)')
    if all_ok:
        print('All verses present ✓')
    chs = sorted(existing.keys(), key=int)
    print(f'Judges mkt-original chapters now: {chs} ({len(chs)}/21)')

if __name__ == '__main__':
    main()
